const KEY = [3, 3, 2, 1, 1, 1, 1, 1, 1, 1, 4, 3, 2, 2, 2, 1, 1, 4, 4, 1, 3, 4, 3, 2, 3, 2, 4, 2, 4, 1, 4, 3, 3, 2, 3, 2, 3, 1, 3, 1, 3, 3, 2, 1, 3, 1, 3, 2, 2, 4, 3, 1, 2, 3, 2, 3, 2, 1, 1, 1, 2, 1, 2, 1, 2, 1, 2, 1, 2, 2, 3, 2, 1, 1, 1, 4, 1, 3, 2, 1, 3, 1, 4, 3, 3, 2, 3, 1, 2, 1, 3, 1, 2, 1, 2, 3, 2, 3, 3, 2];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `Each question has four options. Three of them follow a common pattern or rule. One option does not follow that rule. Identify the odd one out.`, o: [`18 – 3`, `25 – 4`, `32 – 5`, `45 – 6`], e: `Logic: Compare first number with the square of the second number. Created FromEDxaptelanation: Logic: First numCbrerat=ed(seTocoDnadtenumber)² + constant. (a) 3² = 9 18 - 9 = 9 (b) 4² = 16 25 - 16 = 9 (c) 5² = 25 32 - 25 = 7 EXAM TIME UPDATED CREATED S3 MAPPING (d) 6² = 36 45 - 36 = 9 Only option (c) does not follow the same rule. 200 60 Fri, Feb 13, Wed, Jan Vie Final Answer: 32S­el5ection LENGTH 2026, 28, 2026, Final Correct OptioPno:st(c) 12:48:30 14:22:40 Similar Paper (Held on 29 Jul 2025 S3)` },
  { s: `General Intelligence`, q: `A conclusion or inSferleecntcioenis to be drawn from the gLEivNeGnTsHtatement. Choose the oSpelteiocntiotnhat most strongly supports it. 2026, 28, 2026, Sociologist: "RapidPuorsbtanization without adequate infrastructure increases living dPoifsfitculties." 12:48:29 14:15:46 Which of the fol(lGowraidnugasttioante)ments, if true, best supports this view?`, o: [`Many cities generaSteimhiilgahr er revenue after urban expansion.`, `Urban areas attraPcatpsekril(lHedelwdorkers and industries.`, `Cities with fast poopnul2at9ioJnulgrowth face shortages of housing and sanitation.`, `Rural regions expe2r0ie2n5cSe3s)lower economic growth.`], e: `Information Given: Statement: Rapid urbanization without adequate infrastructure increases living difficulties. Task: Choose the statement that best supports this view. Logic: Support must show urban growth causing problems due to lack of facilities. Explanation: Logic: Direct evidence of difficulties from rapid urban population growth. (a) Revenue increase does not show difficulty (b) Skilled workers attraction positive effect (c) Housing and sanitation shortages direct living difficulties (d) Rural growth unrelated Final Answer: Cities with fast population growth face shortages of housing and sanitation. Final Correct Option: (c)` },
  { s: `General Intelligence`, q: `In a family: P is the father of Q. Q is the brother of R. R is the mother of S. T is the wife of P How is T related to Q?`, o: [`Aunt`, `Mother`, `Sister`, `Grandmother`], e: `Information Given: P is father of Q Q is brother of R R is mother of S T is wife of P Final Answer: T is the mother of Q Final Correct Option: (b)` },
  { s: `General Intelligence`, q: `In the following question, select the word that is related to the given pair in the same manner. Erosion : Weathering :: Disease : ?`, o: [`Infection`, `Nutrition`, `Immunity`, `Recovery`], e: `Information Given: Analogy: Erosion : Weathering :: Disease : ? Logic: Identify the relationship between the first pair. Explanation: Logic: Second term is the cause/process of the first. Weathering causes erosion Infection causes disease Check options: (a) Infection cause (b) Nutrition prevention (c) Immunity protection (d) Recovery result Final Answer: Infection Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `In this question, four versions of an office address are provided. Exactly two of them are completely identical. Identify those two and choose the correct option. 1. Surat Circle Second floor within premises Regional Post Office Ring Road Surat ­ 395002 2. Surat Circle Second floor within premises Regional Post Office Ring Road Surat ­ 395002 3. Surat Circle Second Floor within premises Regional Post Office Ring Road Surat ­ 395021 4. Surat Circle Second floor within campus Regional Post Office Ring Road Surat ­ 395002`, o: [`1 and 2`, `2 and 3`, `3 and 4`, `1 and 4`], e: `Information Given: Four versions of an office address are given. Task: Find exactly two addresses that are completely identical (word-for-word). Logic: Addresses must match in spelling, capitalization, wording, and PIN code. Explanation: Logic: Compare each line character-by-character. 1 and 2 Completely identical (same words, same capitalization, same PIN). 3 "Second Floor" (capital F) and PIN 395021 (different). 4 Uses "within campus" instead of "within premises" (different). Short Trick: Check line-by-line: Floor case, premises/campus, and PIN code first. Final Answer: Addresses 1 and 2 are identical. Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `What should come at the place of question mark (?) in the following series? 3, 4, 13, 14, 43, 44, 133, ?`, o: [`134`, `132`, `135`, `144`], e: `Information Given: Series: 3, 4, 13, 14, 43, 44, 133, ? Logic: Pattern alternates between +1 and ×3 + 1. Explanation: Logic: ×3 + 1, then +1 alternately. Step-by-step: 3 4 (+1) 4 13 (4×3 +1) 13 14 (+1) 14 43 (14×3 +1) 43 44 (+1) 44 133 (44×3 +1) 133 134 (+1) Final Answer: 134 Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `A data storage system follows an LSM-tree structure consisting of 4 levels. If level 0 can store 50 records and each higher level can store 8 times the records of the previous level, what is the total storage capacity of the system?`, o: [`29,250`, `29,450`, `30,000`, `28,800`], e: `Information Given: LSM-tree with 4 levels (Level 0 to Level 3) Level 0 capacity = 50 records Each higher level stores 8 times the previous level Formula Used: Geometric progression sum Explanation: Logic: Each level = previous × 8; add all levels. Level 0 = 50 Level 1 = 50 × 8 = 400 Level 2 = 400 × 8 = 3,200 Level 3 = 3,200 × 8 = 25,600 Total = 50 + 400 + 3,200 + 25,600 = 29,250 Short Trick: 4-level LSM add GP terms: a(1 + r + r² + r³) Final Answer: 29,250 Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `In the following question, choose the number that will replace the question mark (?) to complete the analogy: 5 : 60 :: 6 : ?`, o: [`84`, `88`, `90`, `96`], e: `Information Given: Analogy: 5 : 60 :: 6 : ? Logic: Find the operation connecting 5 to 60, then apply it to 6. Explanation: Logic: n × (n + 1) × 2 5 × 6 × 2 = 60 6 × 7 × 2 = 84 Final Answer: 84 Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `Carefully observe the letters in the word DEMOCRATIC. From the options given below, choose the word that can be formed using the letters of the given word, without repeating any letter more than its available frequency.`, o: [`COMRADE`, `ACADEMIC`, `CANDIDATE`, `DIRECTOR`], e: `Information Given: Word: DEMOCRATIC Task: Form a word using available letters without exceeding frequency. Logic: Check letter availability and repetition. Explanation: Logic: Compare letters of each option with DEMOCRATIC. Letters in DEMOCRATIC: D, E, M, O, C, R, A, T, I (a) COMRADE C, O, M, R, A, D, E all available (b) ACADEMIC Needs A ×2 and C ×2 only one A and one C (c) CANDIDATE Needs N ×1, D ×2, A ×2 N missing, repeats (d) DIRECTOR Needs R ×2 only one R Final Answer: COMRADE Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `In a coded language, the word PREDICTION is written as NOITCIDERP. Using the same coding pattern, what will be the code for EXPLANATION?`, o: [`NOITANALPXE`, `NOITALPXEAN`, `NOITALPXENA`, `NOITALPANEX`], e: `Information Given: Coding: PREDICTION NOITCIDERP Word to code: EXPLANATION Explanation: Logic: Reverse the entire word letter by letter. EXPLANATION NOITANALPXE Final Answer: NOITALPANXE Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `Certain numerical operations are defined below. Choose the option that gives the correct result. If X = 4, Y = 5, and Z = 3, what is the value of (50 mode (X + Y) × Z)?`, o: [`21`, `27`, `18`, `23`], e: `Information Given: X = 4, Y = 5, Z = 3 Expression: 50 mod ((X + Y) × Z) (Assumption: mod applies to the whole product) Explanation: Logic: Solve bracket multiply apply mod. Step-by-step: X + Y = 4 + 5 = 9 9 × 3 = 27 50 mod 27 = divide 50 by 27, remaininder = 23 Final Answer: 23 Final Correct Option: (d)` },
  { s: `General Intelligence`, q: `Statement: A manufacturing firm is considering shutting down units that have been running at a loss for several years. The move could impact many workers and the local economy. Unit heads believe productivity will improve, but audit reports indicate repeated financial decline. Senior management is unsure how to proceed. What approach should be adopted to take this decision?`, o: [`immediately shut down all loss-making units to cut expenses`, `continue operating all units to avoid social and employment issues`, `set measurable performance benchmarks with a review period and assess each unit objectively`, `allow individual unit heads to independently decide closure`], e: `Information Given: Loss-making manufacturing units for several years Social and economic impact involved Conflicting views: unit heads optimistic, audits show decline Management unsure Logic: Best decision balances objectivity, data, and social impact. Explanation: Logic: Avoid extreme or biased decisions; use evidence-based review. (a) Immediate shutdown rash, ignores impact (b) Continue all units ignores financial reality (c) Set benchmarks + review balanced, objective, data-driven (d) Unit heads decide biased, inconsistent Final Answer: Set measurable performance benchmarks with a review period and assess each unit objectively. Final Correct Option: (c)` },
  { s: `General Intelligence`, q: `In this question, a situation is described followed by two judgements. Decide which judgement(s) logically follow(s) from the statement. Statement: A company has introduced biometric access cards for all employees. Judgement I: This system will completely eliminate workplace misconduct. Judgement II: This may lead to concerns regarding data security.`, o: [`only judgement i follows`, `only judgement ii follows`, `both judgements i and ii follow`, `neither judgement i nor ii follows`], e: `Information Given: Statement: A company has introduced biometric access cards for all employees. Logic: Judgements must be definitely true, not assumptions or exaggerations. Explanation: Logic: Check certainty vs possibility. Judgement I: "Completely eliminate workplace misconduct" Too extreme; no system guarantees total elimination. Judgement II: "May lead to concerns regarding data security" Logical possibility with biometric data. Final Answer: Only Judgement II follows. Final Correct Option: (b)` },
  { s: `General Intelligence`, q: `In this type of problem, certain conditions are given and you must identify the statement that is definitely true. If ALL CATS ARE MAMMALS and SOME MAMMALS ARE PETS, which of the following conclusions must be true?`, o: [`some cats are pets`, `some mammals are cats`, `all pets are cats`, `no cat is a pet`], e: `Information Given: All cats are mammals. Some mammals are pets. (a) Some cats are pets Not definite Reason: We only know some mammals are pets. Cats are mammals, but it is not given that those "some mammals" include cats. (b) Some mammals are cats Definitely true Reason: From "All cats are mammals", cats exist within mammals. Hence, at least some mammals are cats. (c) All pets are cats False Reason: No statement links all pets exclusively to cats. (d) No cat is a pet Not definite Reason: There is no statement denying a relationship between cats and pets. Cats may or may not be pets. Final Answer: Some mammals are cats Final Correct Option: (b)` },
  { s: `General Intelligence`, q: `In the following question, a situation is described. Choose the most appropriate and socially intelligent course of action. You are part of a project group where one colleague regularly presents shared ideas as solely their own. This has begun to lower team morale. The person does not appear malicious and seems unaware of the impact. You are not the team leader, but others expect you to act. What should you do?`, o: [`confront the colleague openly during a group discussion`, `speak to the colleague privately and explain the effect of taking sole credit on team trust`, `immediately escalate the matter to senior management`, `ignore the situation to avoid conflict`], e: `Information Given: Situation: A colleague takes sole credit for shared ideas, unintentionally affecting team morale. You are not the leader but expected to act. Logic: Best response should be calm, corrective, and preserve team harmony. Explanation: Logic: Address the issue directly but privately to avoid embarrassment or conflict. (a) Open confrontation may escalate tension (b) Private discussion explaining impact constructive and socially intelligent (c) Escalate immediately too harsh for a non-malicious issue (d) Ignore morale will worsen Final Answer: Speak to the colleague privately and explain the effect of taking sole credit on team trust. Final Correct Option: (b)` },
  { s: `General Intelligence`, q: `Some mathematical symbols are defined with specific rules. Check which option gives the correct result. If X Y = (X × Y) - (X + Y), what is the value of 5 4?`, o: [`11`, `9`, `10`, `12`], e: `Information Given: Operation defined: X Y = (X × Y) - (X + Y) Given: X = 5, Y = 4 Explanation: Logic: Multiply first, then subtract the sum. Step-by-step: X × Y = 5 × 4 = 20 X+Y=5+4=9 (X × Y) - (X + Y) = 20 - 9 = 11 Final Answer: 11 Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `Find the appropriate sequence that logically arranges the given administrative units from the smallest to the largest level. Village Council, Sub-division, Region, Province`, o: [`village council, sub-division, region, province`, `province, region, sub-division, village council`, `sub-division, village council, province, region`, `region, village council, sub-division, province`], e: `Information Given: Administrative units: Village Council, Sub-division, Region, Province Task: Arrange from smallest to largest. Logic: Administrative hierarchy increases from local to broader governance. Explanation: Logic: Smallest local body largest administrative unit. Village Council Sub-division Region Province Check options: (a) Correct order (b) Reverse order (c) Incorrect middle order (d) Incorrect starting unit Final Answer: Village council, sub-division, region, province Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `Statement: An organization has implemented remote working options for its staff. Conclusions: I. The organization aims to enhance employee well-being. II. Employees were unable to perform effectively in office-based roles.`, o: [`only i follows`, `only ii follows`, `both follow`, `neither follows`], e: `Information Given: Statement: An organization has implemented remote working options for its staff. Logic: Judgements must be definitely true, not assumed reasons. Explanation: Logic: Check what necessarily follows from introducing remote work. Judgement I: Enhancing employee well-being Possible, but not definite; remote work can be for many reasons. Judgement II: Employees were ineffective in office No such indication given. Final Answer: Neither judgement I nor II follows. Final Correct Option: (d)` },
  { s: `General Intelligence`, q: `In each of the following questions, the second word is derived from the first using a specific pattern that may involve alphabet shifting, reversal, or rearrangement. Apply the same pattern to the third word and choose the correct answer. BRIGHT : ESLHKU :: WINDOW : ?`, o: [`XJOEPX`, `XJMOEP`, `XJOPMX`, `ZJQERX`], e: `Information Given: Analogy: BRIGHT : ESLHKU :: WINDOCWop:y?right © 2026 Adda247 Logic: Letters are shifted alternately by +3, +1 (left to right). Explanation: Logic: Apply +3, +1 repeatedly to each letter. BRIGHT ESLHKU BE (+3) RS (+1) IL (+3) GH (+1) HK (+3) TU (+1) Apply the same to WINDOW: WZ (+3) IJ (+1) NQ (+3) DE (+1) OR (+3) WX (+1) So result = ZJQERX Final Answer: ZJQERX` },
  { s: `General Intelligence`, q: `In the following question, a situation is given. Choose the most appropriate response based on logic and behaviour. In a situation where your colleague appears anxious but avoids discussing the issue, what should you do?`, o: [`speak calmly and allow them time`, `criticize them for being secretive`, `show irritation over their silence`, `compel them to explain immediately`], e: `Information Given: Situation: A colleague appears anxious but avoids discussing the issue. Logic: Choose the response that is supportive, patient, and emotionally intelligent. Explanation: Logic: Best behaviour is calm support without pressure. (a) Speak calmly and allow them time supportive and respectful (b) Criticize negative, worsens anxiety (c) Show irritation discouraging (d) Compel immediately forceful, inappropriate Final Answer: Speak calmly and allow them time. Final Correct Option: (a)` },
  { s: `General Intelligence`, q: `Statements: All novels are books. Some books are testprime. All testprime are educational. Conclusions: I. Some books are educational. II. All novels may be testprime.`, o: [`only i follows`, `only ii follows`, `both i and ii follow`, `neither i nor ii follows`], e: `Information Given: All novels are books. Some books are testprime. All testprime are educational. Conclusion I: Some books are educational Step-by-step: Some books are testprime All testprime are educational Therefore, some books are educational. Definitely true. Conclusion II: All novels may be testprime Step-by-step: All novels are books. Some books are testprime. There is no statement saying novels cannot be testprime. So it is possible that all novels fall within the testprime books. "May be" conclusion is valid. Final Answer: Both conclusions I and II follow. Final Correct Option: (c)` },
  { s: `General Intelligence`, q: `In the following question, four words are given. Three of them belong to the same category. One is different. Identify the word that does not belong to the group.`, o: [`Spinach`, `Lettuce`, `Fenugreek`, `Onion`], e: `Information Given: Words: Spinach, Lettuce, Fenugreek, Onion Logic: Check the category/type of vegetable. Explanation: Logic: Three are leafy vegetables; one is not. Spinach leafy vegetable Lettuce leafy vegetable Fenugreek leafy vegetable Onion bulb/root vegetable Final Answer: Onion Final Correct Option: (d)` },
  { s: `General Intelligence`, q: `Find the odd one out from the following options.`, o: [`rose`, `lotus`, `aloe vera`, `sunflower`], e: `Information Given: Options: rose, lotus, aloe vera, sunflower Logic: Identify the category each belongs to. Explanation: Logic: Three are flowering plants grown mainly for flowers. Rose flowering plant Lotus flowering aquatic plant Sunflower flowering plant Aloe vera medicinal succulent, not grown for flowers Final Answer: Aloe vera Final Correct Option: (c)` },
  { s: `General Intelligence`, q: `A father is 16 years older than his child. After two years, the father's age will become exactly double the child's age. What is the present age of the child?`, o: [`12 years`, `14 years`, `16 years`, `18 years`], e: `Information Given: Father is 16 years older than the child. After 2 years, father's age = 2 × child's age. Explanation: Logic: Form equations from given conditions. Let present age of child = x Father's present age = x + 16 After 2 years: Father = x + 18 Child = x + 2 Condition: x + 18 = 2(x + 2) x + 18 = 2x + 4 x = 14. Final Answer: Present age of the child = 14 years Final Correct Option: (b)` },
  { s: `General Intelligence`, q: `In the following question, a sequence of letters follows a specific rule. Identify the option that will correctly replace the question mark (?). Find the next letter in the series: H, F, D, B, ?`, o: [`L`, `K`, `Z`, `M`], e: `Information Given: Letter series: H, F, D, B, ? Logic: Observe the change in alphabetical positions. Explanation: Logic: Each letter moves backward by 2 positions. H(8) F(6) D(4) B(2) Z(26) (wrap after A) Final Answer: Z Final Correct Option: (c)` },
  { s: `General Awareness`, q: `Flaxseed and soy products are rich sources of ______ which mimic estrogen-like activity in the human body.`, o: [`Alkaloids`, `Phytoestrogens`, `Enzymes`, `Steroids`], e: `The correct answer is (B) Phytoestrogens Explanation: · Phytoestrogens are naturally occurring plant-derived compounds that are structurally or functionally similar to mammalian estrogens and their metabolites. · Flaxseeds are particularly rich in lignans, a type of phytoestrogen, while soy products contain high levels of isoflavones. · These compounds can bind to estrogen receptors in the human body, potentially exerting weak estrogenic or anti-estrogenic effects. · In many plants, phytoestrogens serve as part of the natural defense mechanism against fungi or as part of the plant's internal communication system. · For humans, consuming these can influence hormonal balance and are often studied for their role in heart health and bone density. Information Booster: · Isoflavones (found in so` },
  { s: `General Awareness`, q: `Consider the following statements about the India­France strategic partnership: 1. India and France have adopted a "Horizon 2047" roadmap to deepen their relationship over 25 years. 2. Both countries have agreed to collaborate on developing Small Modular Reactors (SMRs) for civil nuclear energy. 3. France has committed to supporting India's bid for a permanent seat on the UN Security Council. Which of the above is/are correct?`, o: [`Only 1 and 2`, `Only 2 and 3`, `Only 1 and 3`, `1, 2 and 3 are correct`], e: `The correct answer is (D) 1, 2 and 3 are correct Explanation: · The "Horizon 2047" roadmap was adopted during Prime Minister Modi's visit to France in July 2023, marking the 25th anniversary of the Indo- French Strategic Partnership and looking ahead to 2047 (the centenary of India's independence). · The partnership focuses on three pillars: Partnership for Security and Sovereignty, Partnership for the Planet, and Partnership for the People. · Regarding nuclear energy, both nations have agreed to work on Small Modular Reactors (SMRs) and Advanced Modular Reactors (AMRs) to enhance clean energy cooperation. · France has been a consistent and vocal supporter of India's permanent membership in a reformed United Nations Security Council (UNSC). · Defense cooperation remains a cornerstone, with` },
  { s: `General Awareness`, q: `What is one of the major factors contributing to a country's low ranking in the World Happiness Index?`, o: [`High military expenditure`, `Weak social support systems and political instability`, `Excessive industrial growth`, `High population density`], e: `The correct answer is (B) Weak social support systems and political instability Explanation: · The World Happiness Report, published by the UN Sustainable Development Solutions Network, uses six key variables to explain happiness scores: GDP per capita, social support, healthy life expectancy, freedom, generosity, and corruption. · Social support (having someone to count on in times of trouble) is a critical pillar; countries where citizens feel isolated or unsupported by the state/community rank lower. · Political instability and conflict create an environment of fear and uncertainty, which significantly diminishes the subjective well-being of the population. · High levels of perceived corruption in government and business also correlate strongly with low happiness rankings. · Lack of ind` },
  { s: `General Awareness`, q: `Which of the following is NOT considered as high-powered (reserve) money?`, o: [`Currency issued by the central bank`, `Cash reserves of banks with RBI`, `Base money`, `Time deposits with commercial banks`], e: `The correct answer is (D) Time deposits with commercial banks Explanation: · High-powered money, also known as Reserve Money (M0), consists of the total liability of the monetary authority of the country (the RBI in India). · It includes currency in circulation (notes and coins held by the public) and vault cash of commercial banks. · It also includes the deposits held by the Government of India and commercial banks with the RBI. · Time deposits (like Fixed Deposits) are part of broader money aggregates like M3, but they are not considered high-powered money because they cannot be immediately used as a basis for credit creation in the same way reserves can. · High-powered money serves as the basis for the expansion of the money supply through the money multiplier effect. Information Booste` },
  { s: `General Awareness`, q: `Which Indian mission is related to the development of reusable launch vehicle (RLV) technology?`, o: [`RLV-LEX`, `Gaganyaan`, `RISAT-2B`, `Cartosat-3`], e: `The correct answer is (A) RLV-LEX Explanation: · RLV-LEX stands for Reusable Launch Vehicle Autonomous Landing Mission, conducted by ISRO. · The primary goal is to develop essential technologies for a fully reusable launch vehicle to enable low-cost access to space. · In these missions, a winged vehicle is released from a heClicooppytreigrhatn©d p2e0r2fo6rAmdsdaan24a7utonomous landing on a runway, simulating the return of a space shuttle. · This technology is crucial for reducing the cost of satellite launches, as the most expensive parts of the rocket can be recovered and refurbished. · ISRO successfully conducted the RLV LEX-01 and LEX-02 missions at the Aeronautical Test Range (ATR) in Chitradurga, Karnataka. Information Booster: · The final version of RLV will be a Two-Stage-to-Orbit (` },
  { s: `General Awareness`, q: `Consider the following statements about Humayun's Tomb: 1. It was built by Haji Begum in memory of Emperor Humayun. 2. It is located in Delhi and is considered a precursor to the Taj Mahal. 3. It was constructed during the reign of Akbar. Which of the statements given above is/are correct?`, o: [`1, 2 and 3`, `1 and 2 only`, `1 and 3 only`, `2 and 3 only`], e: `The correct answer is (D) 1, 2 and 3 Explanation: · Humayun's Tomb was commissioned by his first wife and chief consort, Empress Bega Begum (also known as Haji Begum), in 1565­1572. · It is the first garden-tomb on the Indian subcontinent and is located in the Nizamuddin East area of Delhi. · It is often called the 'dormitory of the Mughals' because over 150 Mughal family members are buried here. · The tomb introduced the Persian double-dome and the Charbagh (four-quadrant garden) style to India, which reached its pinnacle in the Taj Mahal. · Since the construction started in 1565 and ended in 1572, it falls directly within the reign of Emperor Akbar (1556­1605). Information Booster: · The architect of the tomb was Mirak Mirza Ghiyas, a Persian architect. · It was declared a UNESCO World H` },
  { s: `General Awareness`, q: `Under the Bharatiya Sakshya Adhiniyam (BSA), 2023, which of the following qualifies as an admission?`, o: [`A confession obtained by coercion`, `A statement made by a witness about another person`, `A statement suggesting an inference of fact made by a party to the case`, `An anonymous written statement`], e: `The correct answer is (C) A statement suggesting an inference of fact made by a party to the case Explanation: · The Bharatiya Sakshya Adhiniyam (BSA), 2023, replaced the Indian Evidence Act of 1872 to modernize the rules of evidence in India. · An admission is defined as a statement, oral or documentary (including electronic form), which suggests any inference as to any fact in issue or relevant fact. · It must be made by a party to the proceeding, their agent, or persons having proprietary or pecuniary interest in the subject matter. · Admissions are substantive evidence but are not conclusive proof of the matters admitted; they may operate as estoppels. · The BSA 2023 gives specific recognition to electronic records as primary evidence, aligning with the definition of statements/admissi` },
  { s: `General Awareness`, q: `The Dalli­Rajhara and Bailadila regions are famous for the mining of which mineral?`, o: [`Bauxite`, `Manganese`, `Iron ore`, `Copper`], e: `The correct answer is (C) Iron ore Explanation: · Dalli-Rajhara and Bailadila are located in Chhattisgarh and are home to some of the largest and best-quality iron ore deposits in India. · The iron ore from Dalli-Rajhara is the primary source of raw material for the Bhilai Steel Plant. · The Bailadila range (Dantewada district) contains high-grade hematite ore, which is famous for its high iron content. · A significant portion of the ore from Bailadila is exported to Japan and South Korea through the Visakhapatnam port. · These mines are mechanized and operated by the National Mineral Development Corporation (NMDC) and Steel Authority of India Limited (SAIL). Information Booster: · Bailadila means 'hump of an ox' in the local language, referring to the shape of the mountain range. · Chhatt` },
  { s: `General Awareness`, q: `Which government scheme provides an annual financial benefit of 6,000 to eligible landholding farmer families across India?`, o: [`Pradhan Mantri Fasal Bima Yojana (PMFBY)`, `Pradhan Mantri Kisan Samman Nidhi (PM-KISAN)`, `Pradhan Mantri Krishi Sinchai Yojana (PMKSY)`, `Deendayal Antyodaya Yojana - NRLM`], e: `The correct answer is (B) Pradhan Mantri Kisan Samman Nidhi (PM-KISAN) Explanation: · PM-KISAN is a Central Sector Scheme launched in February 2019 (effective from December 2018) to provide income support to all landholding farmers' families. · Under the scheme, an amount of 6,000 per year is released in three 4-monthly installments of 2,000 each. · The funds are transferred directly into the bank accounts of the beneficiaries through Direct Benefit Transfer (DBT) mode. · Initially, the scheme was for small and marginal farmers (holding up to 2 hectares), but it was later extended to all landholding farmers. · The definition of family for the scheme is husband, wife, and minor children. Information Booster: · The identification of beneficiaries is the responsibility of the State and Union ` },
  { s: `General Awareness`, q: `According to the Constitution of India, what is the maximum strength of a State Legislative Assembly?`, o: [`400`, `450`, `500`, `550`], e: `The correct answer is (C) 500 Explanation: · Article 170 of the Indian Constitution prescribes the composition of the Legislative Assemblies (Vidhan Sabha). · The maximum strength of an assembly is fixed at 500 members, and the minimum strength is 60 members. · However, some states like Sikkim, Goa, and Mizoram have smaller assemblies (e.g., 32, 40) due to their small population and geographical size, which are exceptions provided by Parliamentary acts. · The members are chosen by direct election from territorial constituencies in the State. · The size of the assembly depends on the population of the state, determined after each census (currently based on the 1971 census until 2026). Information Booster: · Uttar Pradesh has the largest Legislative Assembly in India with 403 members. · The ` },
  { s: `General Awareness`, q: `The Nationalisation of major commercial banks in India took place during the ______ Five-Year Plan.`, o: [`Third`, `Fourth`, `Fifth`, `Sixth`], e: `The correct answer is (B) Fourth Explanation: · The first major wave of bank nationalization occurred on July 19, 1969, under the leadership of Prime Minister Indira Gandhi. · During this phase, 14 major commercial banks with deposits exceeding 50 crore were nationalized. · The Fourth Five-Year Plan spanned from 1969 to 1974, thus encompassing this significant economic move. · The goal was to align the banking sector with the socialistic priorities of the government and ensure credit reached rural and agricultural sectors. · Prior to this, banks were largely controlled by industrial houses and focused on urban lending. Information Booster: · A second phase of nationalization took place in 1980 (during the Sixth Plan), where 6 more banks were nationalized. · The 1969 nationalization is cons` },
  { s: `General Awareness`, q: `The formation of bright and dark fringes in Young's double-slit experiment is due to:`, o: [`Reflection of light`, `Refraction of light`, `Superposition of light waves`, `Polarization of light`], e: `The correct answer is (C) Superposition of light waves Explanation: · Young's double-slit experiment (YDSE) is the classic demonstration of the interference of light, proving its wave nature. · When light from a coherent source passes through two cClospeylryigshpta©ced20s2li6ts,Atdhdeaw2a4v7es emerging from the slits spread out and overlap. · Superposition occurs where these two waves meet; if they are in phase, constructive interference creates a bright fringe. · If the waves meet out of phase (crest meets trough), destructive interference occurs, resulting in a dark fringe. · This process creates a stable interference pattern of alternating bright and dark bands on a screen. Information Booster: · For a stable pattern, the sources must be coherent (constant phase difference) and monochro` },
  { s: `General Awareness`, q: `Which of the following folk dances belongs to the state of Chhattisgarh?`, o: [`Panthi`, `Rouf`, `Garba`, `Yakshagana`], e: `The correct answer is (A) Panthi Explanation: · Panthi dance is one of the most important folk dance forms of the Satnami community in Chhattisgarh. · It is performed on Maghi Purnima, the birth anniversary of Guru Ghasidas, the founder of the Satnami sect. · The dance is characterized by rhythm, vigorous movements, and the formation of human pyramids, reflecting the spiritual devotion of the performers. · Performers usually wear white dhotis and dance around a 'Jaitkhamb' (a symbol of their faith) to the accompaniment of traditional instruments like the 'Mridang' and 'Jhanjh'. · Other prominent dances from Chhattisgarh include Raut Nacha, Pandavani, and Karma. Information Booster: · Pandavani is a world-renowned folk ballad from Chhattisgarh, famously performed by Teejan Bai. · Raut Nacha` },
  { s: `General Awareness`, q: `Read the following statements carefully and choose the correct option: Statement 1: India has the largest adolescent population in the world. Statement 2: Adolescence is defined by the WHO as the age group of 10­19 years.`, o: [`Only 1`, `Only 2`, `Both 1 and 2 are correct`, `Neither 1 nor 2 is correct`], e: `The correct answer is (C) Both 1 and 2 are correct Explanation: · Statement 1 is correct: India is home to the largest number of adolescents in the world, totaling approximately 253 million (about one-fifth of the total population). This demographic represents a huge 'demographic dividend' if managed correctly. · Statement 2 is correct: The World Health Organization (WHO) formally defines 'adolescents' as individuals in the 10­19 year age group. · This period is characterized by rapid physical growth, psychological development, and social transition from childhood to adulthood. · The Government of India has various programs like 'Rashtriya Kishor Swasthya Karyakram' (RKSK) to address the health and nutritional needs of this specific group. · Addressing issues like anemia, reproductive heal` },
  { s: `General Awareness`, q: `Consider the following statements about the novel Untouchable by Mulk Raj Anand: Assertion (A): The novel is a powerful critique of the caste system in India. Reason (R): It vividly narrates the single day in the life of Bakha, a sweep who faces continuous discrimination and dehumanization.`, o: [`Both A and R are true, and R correctly explains A.`, `Both A and R are true, but R does not correctly explain A.`, `A is true, but R is false.`, `A is false, but R is true.`], e: `The correct answer is (A) Both A and R are true, and R correctly explains A. Explanation: · Published in 1935, "Untouchable" is one of the most significant works of Indian English literature. · The Assertion (A) is true: Mulk Raj Anand used the novel as a vehicle for social reform, exposing the cruelty and hypocrisy of the caste-based social hierarchy. · The Reason (R) is true and explains (A): By focusing on just one day in the life of Bakha, a young sweeper, Anand demonstrates how pervasive and relentless the discrimination is--from the way he must announce his presence to the abuse he receives for accidentally touching a high-caste man. · The novel concludes with three potential solutions for Bakha's plight: conversion to Christianity, the Gandhian approach of social change, or the intr` },
  { s: `General Awareness`, q: `Which of the following statements about the Mughal Jagirdari system is/are correct? Statement I: Jagirs were transferable and not hereditary. Statement II: Jagirdars collected revenue on behalf of the state.`, o: [`Only I`, `Only II`, `Both I and II`, `Neither I nor II`], e: `The correct answer is (C) Both I and II Explanation: · The Jagirdari system was a key administrative and land revenue mechanism under the Mughals where state officers (Mansabdars) were assigned land (Jagirs) instead of cash salaries. · Statement I is correct: To prevent local power bases from forming, the Mughal emperors regularly transferred Jagirdars from one region to another (usually every 3-4 years). They were not hereditary owners. · Statement II is correct: The primary duty of a Jagirdar was to collect land revenue (Mal) from the assigned territory as per state assessment and use it to maintain their required military contingent and personal expenses. · The system was highly centralized under Akbar but began to face a 'Jagirdari crisis' during the later Mughal period, leading to the` },
  { s: `General Awareness`, q: `Read the following statements and choose the correct option: Statement 1: The Deccan Plateau is bounded by the Western Ghats on the west and the Eastern Ghats on the east. Statement 2: Most rivers of the Deccan Plateau flow eastward into the Bay of Bengal.`, o: [`Only 1`, `Only 2`, `Both 1 and 2 are correct`, `Neither 1 nor 2 is correct`], e: `The correct answer is (C) Both 1 and 2 are correct Explanation: · The Deccan Plateau is a large triangular plateau in India, making up most of the southern part of the country. · Statement 1 is correct: It is geographically bordered by the Satpura and Vindhya ranges to the north, the Western Ghats (Sahyadri) to the west, and the Eastern Ghats to the east. · Statement 2 is correct: The plateau is tilted from west to east. Because of this general slope, major rivers like the Godavari, Krishna, and Kaveri originate in the Western Ghats and flow eastward across the plateau to drain into the Bay of Bengal. · The Western Ghats are higher and more continuous than the Eastern Ghats, which are lower and broken by river valleys. · The black soil (regur) found in the northwestern part of the plateau ` },
  { s: `General Awareness`, q: `Consider the following statements about the Bay of Bengal Initiative for Multi-Sectoral Technical and Economic Cooperation (BIMSTEC): 1. It is a regional organization comprising all eight SAARC member states. 2. It serves as a bridge between South Asia and Southeast Asia. 3. Pakistan is a member country of BIMSTEC. Which of the statements given above is/are correct?`, o: [`1 only`, `2 only`, `1 and 3 only`, `None of the above`], e: `The correct answer is (B) 2 only Explanation: · BIMSTEC is a regional organization that came into being on June 6, 1997, through the Bangkok Declaration. · Statement 1 is incorrect: It does not include all SAARC members. It comprises seven members: five from South Asia (Bangladesh, Bhutan, India, Nepal, Sri Lanka) and two from Southeast Asia (Myanmar, Thailand). · Statement 2 is correct: By including countries from both South and Southeast Asia, BIMSTEC acts as a platform for cooperation between the two regions, aligning with India's 'Act East' policy. · Statement 3 is incorrect: Pakistan is not a member of BIMSTEC. This is one reason why India has prioritized BIMSTEC over SAARC in recent years, as SAARC meetings have been stalled due to regional tensions. · The organization focuses on 14 ` },
  { s: `General Awareness`, q: `Consider the following statements regarding India's climate commitments: 1. India aims to reduce the emissions intensity of its GDP by 45% by 2030 from 2005 levels. 2. India has committed to achieve net-zero emissions by 2070. 3. India's updated NDC includes achieving 50% non-fossil fuel­based electricity capacity by 2025. Which of the statements given above is/are correct?`, o: [`1 and 2 only`, `1 and 3 only`, `2 and 3 only`, `1, 2 and 3`], e: `The correct answer is (A) 1 and 2 only Explanation: · Statement 1 is correct: As part of its updated Nationally Determined Contributions (NDCs) submitted in 2022, India pledged to reduce the emissions intensity of its GDP by 45% by 2030, compared to the 2005 level. · Statement 2 is correct: Prime Minister Modi announced at COP26 in Glasgow (2021) that India will achieve the target of net-zero emissions by the year 2070. · Statement 3 is incorrect: The target to achieve about 50% cumulative electric power installed capacity from non-fossil fuel-based energy resources is set for 2030, not 2025. · These commitments are part of India's 'Panchamrit' strategy to combat climate change. · India is also working toward creating an additional carbon sink of 2.5 to 3 billion tonnes of CO2 equivalent t` },
  { s: `General Awareness`, q: `Consider the following statements marked as Assertion (A) and Reason (R). Mark the correct options: Assertion (A): Karnam Malleswari was the first Indian woman to win an Olympic medal. Reason (R): She achieved this historic feat by winning a gold medal in weightlifting at the 2000 Sydney Olympics.`, o: [`Both A and R are true, and R correctly explains A.`, `Both A and R are true, but R does not explain A.`, `A is true, but R is false.`, `A is false, but R is true.`], e: `The correct answer is (C) A is true, but R is false. Explanation: · Assertion (A) is correct: Karnam Malleswari made history at the 2000 Sydney Olympics by becoming the first Indian woman ever to win an Olympic medal. · Reason (R) is incorrect: She did not win a gold medal; she won a bronze medal in the 69 kg weightlifting category. · She lifted 110 kg in the 'snatch' and 130 kg in the 'clean and jerk' for a total of 240 kg. · Her achievement was a landmark moment for women's sports in India, breaking a long drought and inspiring a generation of female athletes. · Before her, only Indian men (in hockey, wrestling, and tennis) had won Olympic medals for independent India. Information Booster: · She was awarded the Rajiv Gandhi Khel Ratna (now Major Dhyan Chand Khel Ratna) in 1995. · She als` },
  { s: `General Awareness`, q: `Match the following Archery terms with their correct meanings: Column A (Terms) Column B (Meanings)`, o: [`A-1, B-2, C-3, D-4`, `A-2, B-1, C-4, D-3`, `A-3, B-2, C-1, D-4`, `A-1, B-3, C-2, D-4`], e: `The correct answer is (A) A-1, B-2, C-3, D-4 Explanation: · Bullseye: In competitive archery, this is the gold-colored center of the target, which awards the maximum points (usually 10). · Quiver: This is a container or holder specifically designed to carry arrows safely, which can be worn on the archer's back, waist, or attached to the bow. · Draw Length: This refers to the distance an archer pulls the bowstring back from the resting position to their anchor point at full draw. · Nocking Point: This is the specific spot on the bowstring where the end of the arrow (the nock) is attached before firing. · Understanding these terms is essential for both Olympic archery and traditional practices. Information Booster: · Archery is the national sport of Bhutan. · In the Olympics, the distance fr` },
  { s: `General Awareness`, q: `Which of the following best describes the role of Foreign Institutional Investors (FIIs) in India?`, o: [`Providing subsidies to farmers`, `Financing government welfare schemes`, `Investing in India's equity and debt markets`, `Funding rural employment programmes`], e: `The correct answer is (C) Investing in India's equity and debt markets Explanation: · FIIs (Foreign Institutional Investors) are investment funds or entities that invest in a country outside of the one in which they are registered or headquartered. · In India, they play a crucial role by bringing in foreign capital into the stock exchanges (equity) and the bond markets (debt). · They are regulated by the Securities and Exchange Board of India (SEBI). · FII investment is often referred to as 'hot money' because it can be withdrawn quickly, leading to volatility in the exchange rate and stock market indices. · Their entry increases liquidity in the Indian markets and provides necessary capital for Indian companies to expand. Information Booster: · In 2014, SEBI introduced the Foreign Portfol` },
  { s: `General Awareness`, q: `Who launched the nationwide campaign "Viksit Bharat @2047"?`, o: [`Amit Shah`, `Narendra Modi`, `Rajnath Singh`, `Jagdeep Dhankhar`], e: `The correct answer is (B) Narendra Modi Explanation: · Prime Minister Narendra Modi launched 'Viksit Bharat @2047: Voice of Youth' in December 2023 via video conferencing. · The initiative aims to provide a platform for the youth of the country to contribute ideas to the vision of making India a developed nation by 2047, the centenary of its independence. · The campaign focuses on various aspects of development including economic growth, social progress, environmental sustainability, and good governance. · It encourages students and young professionals to share their suggestions through the MyGov portal. · The PM emphasized that the youth are both the 'agents of change' and the 'beneficiaries' of a developed India. Information Booster: · The vision involves transforming India into a US $30` },
  { s: `General Awareness`, q: `Match the geological period with the mass extinction event that marked its end: Column A (Period) Column B (Extinction Event) 1. Permian A. End-Cretaceous (K­Pg) extinction 2. Cretaceous B. End-Devonian extinction 3. Devonian C. End-Permian ("The Great Dying") extinction Choose the correct answer:`, o: [`1-A, 2-C, 3-B`, `1-C, 2-A, 3-B`, `1-B, 2-A, 3-C`, `1-C, 2-B, 3-A`], e: `The correct answer is (B) 1-C, 2-A, 3-B Explanation: · Permian Period (1-C): The End-Permian extinction, often called "The Great Dying," occurred about 252 million years ago. It is the most severe extinction event in Earth's history, wiping out over 90% of marine species and 70% of terrestrial vertebrates. · Cretaceous Period (2-A): The End-Cretaceous extinction (K-Pg) happened about 66 million years ago. It is famous for the extinction of non-avian dinosaurs, likely caused by a massive asteroid impact and volcanic activity. · Devonian Period (3-B): The Late Devonian mass extinctioCnoopcycruigrrhetd©ro2u0g2h6lyA3d7d5a2m4i7llion years ago, primarily affecting marine life like corals and trilobites. · These are part of the 'Big Five' mass extinctions that have shaped the evolution of life on` },
  { s: `General Awareness`, q: `Consider the following statements: 1. The President can dissolve the Lok Sabha only on the advice of the Council of Ministers. 2. The Governor plays a discretionary role in appointing the Chief Minister in a hung Assembly. 3. A Money Bill can be introduced only with the prior recommendation of the President. Which of the above statements is/are correct?`, o: [`1 and 2 only`, `2 and 3 only`, `1 and 3 only`, `1, 2 and 3`], e: `The correct answer is (D) 1, 2 and 3 Explanation: · Statement 1 is correct: Under Article 85, the President has the power to dissolve the Lok Sabha. However, as per the constitutional convention and the 42nd/44th Amendments, this is done on the aid and advice of the Council of Ministers headed by the PM. · Statement 2 is correct: While the Governor normally appoints the leader of the majority party, in a 'hung assembly' (where no single party has a clear majority), the Governor uses situational discretion to invite the person most likely to command a majority. · Statement 3 is correct: Under Article 117, a Money Bill (defined in Article 110) cannot be introduced in the Lok Sabha without the prior recommendation of the President. · These provisions highlight the role of the executive in the` },
  { s: `Quantitative Aptitude`, q: `A train crosses a 200-meter-long platform in 30 seconds and a man standing on the platform in 18 seconds. What is the length of the train?`, o: [`250 m`, `280 m`, `300 m`, `320 m`], e: `Given: Time for platform (30s) corresponds to Distance = Train + Platform. Time for man (18s) corresponds to Distance = Train. Platform Length = 200m. Formula Used: Speed = Distance / Time Solution: Let Train Length = L. L Speed S = 18 L + 200 Also, S = 30 Equating speeds: L L + 200 = 18 30 L L + 200 = 3 5 5L = 3(L + 200) 5L = 3L + 600 2L = 600 L = 300 m Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `From the top of a 100 m high tower, the angle of depression of a car changes from 30° to 45°. What is the distance travelled by the car during this observation?`, o: [`100(√3 − 1) m`, `100(√3 + 1) m`, `50(√3 − 1) m`, `100√3 m`], e: `d₁ = 100 cot 30° = 100√3, d₂ = 100 cot 45° = 100. Distance = d₁ − d₂ = 100(√3 − 1) m. Option A.` },
  { s: `Quantitative Aptitude`, q: `The value of: (2 + √3) + 1/(2 − √3) − (4 + 2√3) is:`, o: [`1`, `0`, `2`, `4`], e: `Rationalize 1/(2 − √3) = (2 + √3)/(4 − 3) = 2 + √3. Expression = (2 + √3) + (2 + √3) − (4 + 2√3) = 0. Option B.` },
  { s: `Quantitative Aptitude`, q: `A shopkeeper bought 50 vases for 5000. 5 vases were broken during transport. At what price per vase should he sell the remaining vases to make an overall profit of 10%?`, o: [`120.50`, `115.33`, `122.22`, `110.00`], e: `Given: Total Cost Price (CP) = 5000 Total vases = 50 Broken vases = 5 Remaining vases = 45 Desired Profit = 10% Formula Used: SP = CP × (1 + P% ) 100 Solution: Calculate Total Selling Price needed: Total SP = 5000 × 110 = 5500 100 Calculate SP per remaining vase: SP per vase = Total SP Remaining Vases SP per vase = 5500 45 SP per vase = 1100 122.22 9 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A and B invest 60,000 and 40,000, respectively. After one year, the total profit is 30,000. Determine A's share of the profit.`, o: [`12,000`, `18,000`, `15,000`, `20,000`], e: `Given: Investment A = 60,000 Investment B = 40,000 Total Profit = 30,000 Time = 1 year (same for both) Formula Used: Ratio of Profit = Ratio of Investment (when time is equal) Solution: Calculate the ratio of investments: A : B = 60000 : 40000 A:B=6:4=3:2 Calculate A's share: 3 A's Share = × 30000 3+2 3 A's Share = × 30000 5 A's Share = 3 × 6000= 18000 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A 60-litre mixture of milk and water is in the ratio 2:1. Some of it is removed and replaced with pure milk. The final ratio becomes 5:1. How much of the mixture was replaced?`, o: [`20 litres`, `24 litres`, `30 litres`, `36 litres`], e: `Given: Initial mixture = 60L (Ratio 2:1) Final Ratio = 5:1 Replacement is with Milk. Formula Used: Concentration of constant component (Water). Solution: 1 Initial Water amount = × 60= 20 L. 3 Let x litres of mixture be removed and replaced by milk. 1 When x litres are removed, water removed = x. 3 x Remaining Water = 20 - . 3 Since only milk is added, the amount of water remains the same in the final mixture calculation conceptually, but the total volume is restored to 60L. In the final mixture (60L), Water ratio is 1/(5+1) = 1/6. 1 Final Water amount = × 60= 10 L. 6 Equating the water content: x 20 - = 10 3 x 10 = 3 x = 30 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Simplify: √128 + √72 − √32`, o: [`8√2`, `10√2`, `12√2`, `6√2`], e: `√128 = 8√2, √72 = 6√2, √32 = 4√2. Sum = 8√2 + 6√2 − 4√2 = 10√2. Option B.` },
  { s: `Quantitative Aptitude`, q: `Items are produced by three machines X, Y, Z producing 40%, 35%, and 25% of the total respectively. Their defect rates are 2%, 1%, and 4%. What is the probability that a randomly chosen item is defective?`, o: [`0.0215`, `0.0195`, `0.0225`, `0.0205`], e: `Given P(X) = 0.40, D(X) = 0.02 P(Y) = 0.35, D(Y) = 0.01 P(Z) = 0.25, D(Z) = 0.04 Formula Used Total Probability = P (M achine) × P (Def ectM achine) Solution P(Defect) = (0.40 × 0.02) + (0.35 × 0.01) + (0.25 × 0.04) P(Defect) = 0.008 + 0.0035 + 0.0100 P(Defect) = 0.0215 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `What is the compound interest on a sum of 20,000 for 9 months at 20% p.a., compounded quarterly?`, o: [`3,152.5`, `3,310`, `3,000`, `2,800`], e: `Given: Principal (P) = 20,000 Rate (R) = 20% p.a. Time = 9 months Compounded Quarterly Formula Used: R/4 4n A = P (1 + ) 100 CI = A - P Solution: 20 Rate per quarter = = 5% 4 9 Time in quarters (n) = × 4 = 3 quarters 12 53 A = 20000 (1 + ) 100 A = 20000 ( 21 3 20 ) 9261 A = 20000 × 8000 A= 20000 × 9261 8000 A = 2.5 × 9261 = 23152.5 CI = 23152.5 - 20000 = 3152.5 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A can finish a task in 12 days and B in 15 days. They take a contract for 27,000. Assisted by C, they complete the job in 4 days. What is C's share of the money?`, o: [`10,800`, `12,000`, `9,000`, `13,500`], e: `Given: A's time = 12 days B's time = 15 days Time taken by (A+B+C) = 4 days Total Wages = 27,000 Formula Used: Wages are distributed in proportion to the work done. Solution: 41 Work done by A in 4 days = = 12 3 4 Work done by B in 4 days = 15 Remaining work done by C: W orkC = 1 - 1 + 4 ( ) 3 15 54 W orkC = 1 - ( + ) 15 15 W orkC = 1- 9 62 = = 15 15 5 2 C's Share = × 27000 5 C's Share = 2 × 5400 = 10800 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Find the least number which leaves a remainder of 2 when divided by 6, 9, and 12.`, o: [`36`, `38`, `40`, `42`], e: `Given: Divisors: 6, 9, 12 Remainder: 2 Formula Used: Least Number = LCM(Divisors) + Remainder Solution: First, find the LCM of 6, 9, and 12. Prime factorization: 6 = 2 × 3 9 = 32 12 = 22 × 3 LCM = 22 × 32 = 4 × 9 = 36 Required Number = LCM + 2 Required Number = 36 + 2 = 38 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The mean of five consecutive even numbers is 54. What is the smallest of these numbers?`, o: [`50`, `52`, `48`, `46`], e: `Given: Mean of 5 consecutive even numbers = 54 Formula Used: For an odd number of consecutive terms in an AP, the Mean is equal to the Middle Term. Solution: Since there are 5 numbers, the 3rd number is the mean. 3rd number = 54. The numbers are consecutive even integers. We step back by 2 to find the previous numbers. 2nd number = 54 - 2 = 52 1st number (Smallest) = 52 - 2 = 50 The series is: 50, 52, 54, 56, 58. Smallest number is 50. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The sum of 30% of a number and 20% of the same number is 450. What is 80% of that number?`, o: [`600`, `720`, `800`, `900`], e: `Given: 30% of x + 20% of x = 450 Solution: Let the number be x. 3 0%x + 20%x = 450 50%x = 450 0.5x = 450 450 x = = 900 0.5 Now, find 80% of the number: 80 8 0% of 900 = × 900 100 = 80 × 9 = 720 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A solid sphere of radius R is melted to form two identical smaller spheres of radius r. What is the relation between R and r?`, o: [`R = 3 2r`, `R = 2r`, `R = 3 4r`, `R = 2r`], e: `Given: Volume of Big Sphere = 2 \\times Volume of Small Sphere Formula Used: Volume = 4 r3 3 Solution: 4 R3 = 2 × ( 4 r3) 3 34 Cancel common terms ( ) : 3 R3 = 2r3 Take cube root on both sides: R = 3 2r Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `If a² + 1/a² = 23, find the value of a⁴ + 1/a⁴.`, o: [`529`, `527`, `531`, `525`], e: `(a² + 1/a²)² = a⁴ + 2 + 1/a⁴ = 23² = 529. So a⁴ + 1/a⁴ = 527. Option B.` },
  { s: `Quantitative Aptitude`, q: `If sec A − tan A = p, express sec A in terms of p.`, o: [`(p² + 1)/(2p)`, `(1 − p²)/(2p)`, `(p² − 1)/(2p)`, `(1 + p²)/p`], e: `sec²A − tan²A = 1 → (sec A − tan A)(sec A + tan A) = 1. Given sec A − tan A = p, so sec A + tan A = 1/p. Adding: 2 sec A = p + 1/p = (p² + 1)/p, so sec A = (p² + 1)/(2p). Option A.` },
  { s: `Quantitative Aptitude`, q: `Two semicircles of radius 14 cm are attached to the opposite shorter sides of a rectangle. The length of the rectangle is 28 cm. What is the total area of the figure?`, o: [`1400cm2`, `1008 cm2`, `1124 cm2`, `1232 cm2`], e: `Given: Radius of semicircles (r) = 14 cm Length of rectangle (L) = 28 cm Width of rectangle (B) = 14 cm (Derived from answer key context) Formula Used: Area = Area of Rectangle + Area of 2 Semicircles Area = L × B + r2 Solution: Area of 2 semicircles = Area of 1 circle = 22 × 14 × 14 = 616cm2. 7 Area of rectangle = 28 × 14 = 392cm2. Total Area = 616 + 392 = 1008cm2. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The data given below shows the marks obtained by 9 students: 12, 45, 23, 67, 45, 12, 89, 54, 33. Find the median marks.`, o: [`45`, `54`, `33`, `23`], e: `Given: Marks: 12, 45, 23, 67, 45, 12, 89, 54, 33 N = 9 (odd) Formula Used: Median = N + 1 )th term after arranging in ascending order. ( 2 Solution: Arrange data: 12, 12, 23, 33, 45, 45, 54, 67, 89 Position = (9+1)/2 = 5th term. 5th term is 45. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A quadrilateral ABCD circumscribes a circle. If AB = 8 cm, BC = 9 cm, and CD = 6 cm, find the length of AD.`, o: [`7 cm`, `5 cm`, `4 cm`, `6 cm`], e: `Given: AB = 8, BC = 9, CD = 6 Quadrilateral circumscribes a circle. Formula Used: Sum of opposite sides is equal. AB + CD = BC + AD Solution: 8 + 6 = 9 + AD 14 = 9 + AD AD = 14 - 9 AD = 5 cm Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Calculate the coefficient of mean deviation from the mean for the data: 10, 20, 30, 40, 50.`, o: [`0.2`, `0.4`, `0.5`, `0.33`], e: `Given: Data: 10, 20, 30, 40, 50 Formula Used: Mean (x) = x N x - x Mean Deviation (MD) = MD N Coefficient = x Solution: Sum = 150, N = 5 Mean = 150/5 = 30 Deviations (|x - 30|): |10-30|=20 |20-30|=10 |30-30|=0 |40-30|=10 |50-30|=20 Sum of Deviations = 60 MD = 60/5 = 12 12 12 Coefficient = 30 = 0.4 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The complement of an angle x is equal to (2x - 15). Find the angle x.`, o: [`25`, `30`, `35`, `40`], e: `Given: Complement of x = 90 - x Condition: 90 - x = 2x - 15 Formula Used: Complementary angles sum to 90. Solution: 90 + 15 = 2x + x 105 = 3x 105 x= 3 x = 35 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `In a right-angled triangle with sides 6 cm, 8 cm, and 10 cm, find the inradius.`, o: [`1 cm`, `2 cm`, `3 cm`, `1.5 cm`], e: `Given: Sides: P = 6, B = 8, H = 10 Formula Used: Inradius (r) = P +B-H 2 Solution: r= 6 + 8 - 10 2 r= 14 - 10 42 r = = 2 cm 2 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `What is the y-intercept of the line 3x + 4y = 24?`, o: [`6`, `8`, `4`, `3`], e: `Given: Equation: 3x + 4y = 24 Formula Used: For y-intercept, set x = 0. Solution: Substitute x = 0 in the equation: 3(0) + 4y = 24 4y = 24 y=6 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `PQR is an equilateral triangle inscribed in a circle. Points S and T are on the major and minor arcs respectively. Find QSRand QTR.`, o: [`60, 120`, `30, 150`, `60, 100`, `45, 135`], e: `Given: Equilateral PQR, so QPR = 60. S on major arc, T on minor arc. Formula Used: Angles in the same segment are equal. Opposite angles of a cyclic quadrilateral sum to 180. Solution: For S (major arc): QSRand QPRare in the same segment. QSR = QPR = 60. For T (minor arc): PQRT is a cyclic quadrilateral. QPR + QTR = 180 60 + QTR = 180 QTR = 120. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The base of a right prism is an equilateral triangle with side 10 cm. The height of the prism is 15 cm. What is the total surface area?`, o: [`450 + 50 3cm2`, `300 + 25`, `450 + 100 3cm2`, `400 + 50`], e: `Given: Base: Equilateral triangle, side a = 10 cm Height (h) = 15 cm Formula Used: TSA = Lateral Surface Area + 2(Base Area) LSA = Perimeter × Height Base Area = 43 a2 Solution: Perimeter = 3 × 10 = 30 cm LSA = 30 × 15 = 450cm2 3 3cm2 Base Area = (100)= 25 4 TSA = 450 + 2(25 3) TSA = 450 + 50 3 Final Answer So the correct answer is (a)` },
  { s: `English Language`, q: `A sentence is provided in direct speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding indirect speech. "So intense was his fear that he could scarcely speak," said the doctor.`, o: [`The doctor said he was intensely fearful and scarcely spoke.`, `The doctor said his fear was so intense that he had scarcely spoken.`, `The doctor said that so intense had his fear been that he could scarcely speak.`, `The doctor said that his fear was so intense that he could scarcely speak.`], e: `The correct option is (d). Rule (Direct to Indirect Speech): When reporting a statement: Remove quotation marks and convert to a reporting clause with said that (that is often optional but acceptable). Change pronouns according to the speaker and listener (his remains his). Change tense if required (backshift) unless the statement is still true or context keeps it same. Here, the doctor's statement is a general reporting of a condition at that time, so simple past "said" commonly keeps "was" and modal "could" as they already indicate past context. Maintain meaning, not the special inverted word order used for emphasis in direct speech. Given direct speech: "So intense was his fear that he could scarcely speak," said the doctor. The part "So intense was his fear" is an inversion for emphasi` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful passage. 1. The pages are processed to extract text using OCR tools. 2. The original sheets are uploaded as scanned images. 3. Mistakes in the extracted text are corrected manually. 4. The final file is saved as a searchable PDF.`, o: [`2-1-3-4`, `1-2-3-4`, `1-3-2-4`, `2-3-1-4`], e: `The correct option is (a). Logical sequence (process-based ordering): The sentences describe a step-by-step workflow of converting scanned pages into a searchable PDF. The correct order must follow the real operational sequence. Step 1 (2): First, the physical/original sheets must be uploaded as scanned images. Without scanning/uploading, there are no pages to process. Step 2 (1): After uploading, the pages are processed using OCR to extract text from images. Step 3 (3): OCR can produce errors, so mistakes are corrected manually after extraction. Step 4 (4): Finally, after corrections, the document is saved as a searchable PDF. Why other options are incorrect: (B) starts with processing before uploading scanned images, which is illogical. (C) begins with OCR processing and manual correctio` },
  { s: `English Language`, q: `Identify the misspelt word:`, o: [`Dialectic`, `Solipsism`, `Existantialism`, `Determinism`], e: `The correct option is (c). Spelling check: Option (C) "Existantialism" is misspelt. The correct spelling is "Existentialism". Meaning (minimum 2 lines): "Existentialism" is a philosophical view focusing on individual existence, freedom, and choice, emphasizing that people create meaning through their actions. (Hindi meaning: ) Example: Many modern novels reflect existentialism by showing characters struggling to find meaning in life. Parts of speech: "Existentialism" is a noun (name of a philosophy). The related adjective is "existential." Meanings of all the given options: (A) Dialectic: logical discussion of ideas and contradictions to reach truth (Hindi: / - ). (B) Solipsism: the view that only one's own mind is sure to exist (Hindi: /- ). (C) Existantialism: incorrect spelling of "exis` },
  { s: `English Language`, q: `Pick the correctly spelt word meaning "a skilled craft worker."`, o: [`Artizan`, `Artisan`, `Artesen`, `Artisen`], e: `The correct option is (b). Spelling and meaning: Option (B) "Artisan" is correctly spelt. An artisan is a skilled craft worker who makes things by hand, often with traditional techniques and high workmanship. (Hindi meaning: / ) Example: The village artisan crafted beautiful wooden toys for the festival. Meanings of all the given options: (A) Artizan: incorrect spelling (intended word: artisan). (B) Artisan: skilled craft worker (Hindi: ). (C) Artesen: incorrect spelling (intended word: artisan). (D) Artisen: incorrect spelling (intended word: artisan). Parts of speech: "Artisan" is mainly a noun (an artisan). It can also be used as an adjective in phrases like "artisan bread" (meaning crafted in a traditional way). So the correct answer is (b)` },
  { s: `English Language`, q: `Change the following from active to passive: The advisory panel might have been ignoring crucial inconsistencies in the dataset before the inspection.`, o: [`Crucial inconsistencies in the dataset might have been being ignored by the advisory panel before the inspection.`, `Crucial inconsistencies were ignored by the panel before the inspection.`, `Crucial inconsistencies might have ignored the panel before the inspection.`, `Crucial inconsistencies had been ignored during the inspection.`], e: `The correct option is (a). Given (Active): "The advisory panel might have been ignoring crucial inconsistencies in the dataset before the inspection." Identify the structure: Modal + perfect continuous: might have been + V1-ing (ignoring) Object: "crucial inconsistencies in the dataset" Rule (Active to Passive with modal perfect continuous): Active: Subject + might have been + V1-ing + Object Passive: Object + might have been being + V3 + (by + Subject) Conversion steps: Make the object "crucial inconsistencies in the dataset" the subject of the passive sentence. Keep the modal "might" and perfect continuous idea intact: "might have been being". Change "ignoring" (V1-ing) to "ignored" (V3) because passive requires past participle. Add the agent "by the advisory panel". Keep the time phrase` },
  { s: `English Language`, q: `Why other options are incorrect: Changes meaning/tense: “were ignored” is simple past passive, losing modal and continuous aspect. Grammatically wrong: the object cannot “ignore” the subject in this meaning. Wrong time reference and tense; also changes “before the inspection” to “during the inspection.” So the correct answer is (a)`, o: [`Assurance`, `Approval`, `Agitation`, `Verification`], e: `The correct option is (c). REPOSE: Repose means a state of rest, relaxation, or calmness; it can also mean peacefulness or quiet rest. (Hindi meaning: / ) Example (given word): After the examination, he finally enjoyed a brief period of repose. Correct antonym (C) AGITATION: Agitation means disturbance, restlessness, or a state of anxiety and turbulence; it is the opposite of calm rest. (Hindi meaning: / ) Example (correct word): The unexpected news created agitation among the residents. Synonyms (of REPOSE): rest, calm, relaxation, tranquility. Antonyms (of REPOSE): agitation, unrest, disturbance, anxiety. Meanings of all the other given options: (A) Assurance: a promise or confidence; certainty (Hindi: ). (B) Approval: acceptance or permission; favorable opinion (Hindi: ). (D) Verificati` },
  { s: `English Language`, q: `Choose the most suitable option to replace the highlighted part of the sentence: "The manager would rather the team finishes the project before the weekend begins."`, o: [`finished`, `had finished`, `finish`, `will finish`], e: `The correct option is (a). Key rule (Would rather): When we use "would rather" to express preference about another person's action, we commonly use the past simple form after the subject (even though the meaning is present/future preference). Structure: Subject + would rather + (that) + subject + V2 (past simple) This is similar in idea to the unreal/desired situation pattern (preference, not actual past time). Given sentence: "The manager would rather the team finishes the project ..." "finishes" is present tense and does not follow the expected pattern after "would rather" in this meaning. We should use "finished" (past simple) to show the preferred action. Correct sentence: "The manager would rather the team finished the project before the weekend begins." Why other options are incorrec` },
  { s: `English Language`, q: `What is the best synonym for "incommensurable" in the sentence: "rival frameworks are often incommensurable". Read the passage and answer the question: "Routine scientific inquiry--the work in which most researchers spend the bulk of their careers--rests on a quiet confidence that the community already possesses a dependable picture of how the world functions. To protect that confidence, investigators often narrow their attention to questions the prevailing framework has already marked as legitimate. When inquiry proceeds in this manner, results are typically incremental: they consolidate the dominant model instead of destabilizing it. Gradually, however, irregular findings--observations that resist explanation within the accepted framework--begin to accumulate. At first, such irregularities are treated as measurement mistakes or puzzles that will eventually be resolved without altering the underlying theory. Yet as their frequency and explanatory weight increase, they weaken trust in the reigning framework. "What makes these upheavals especially striking is that the rival frameworks are often incommensurable--they cannot be measured by the same standards of explanation." When such strain reaches a threshold, resolution does not occur through a simple act of refutation, as strict falsificationism might imply, but through a reorientation in how scientists perceive and organize reality. A scientific revolution occurs when a rival framework arises--not as a minor revision but as a deep re-construction of the conceptual world. The shift is not purely deductive; it resembles a sudden change of perception, like an optical reversal. The shift to heliocentrism, for instance, did not merely refine calculations; it transformed the lens through which celestial movement was interpreted. Likewise, relativity did not merely adjust classical mechanics; it displaced core assumptions about space and time."`, o: [`Identical`, `Symmetrical`, `Compatible`, `Incompatible`], e: `The correct option is (d). Given word: "Incommensurable" Meaning (minimum 2 lines): "Incommensurable" means not comparable by the same standard or not measurable in the same terms. It refers to things so different that they cannot be judged using a common scale. (Hindi meaning: / ) Context from passage: The passage states that rival frameworks are "incommensurable" because they cannot be measured by the same standards of explanation. That directly indicates they are incompatible for direct comparison under one set of rules. Option analysis: (D) Incompatible fits best because it conveys that the two frameworks cannot be matched under the same explanatory standards. (C) Compatible is the opposite, so it cannot be correct. (A) Identical and (B) Symmetrical do not match the meaning; "incommens` },
  { s: `English Language`, q: `What does the phrase "optical reversal" imply in this context? Read the passage and answer the question: "Routine scientific inquiry--the work in which most researchers spend the bulk of their careers--rests on a quiet confidence that the community already possesses a dependable picture of how the world functions. To protect that confidence, investigators often narrow their attention to questions the prevailing framework has already marked as legitimate. When inquiry proceeds in this manner, results are typically incremental: they consolidate the dominant model instead of destabilizing it. Gradually, however, irregular findings--observations that resist explanation within the accepted framework--begin to accumulate. At first, such irregularities are treated as measurement mistakes or puzzles that will eventually be resolved without altering the underlying theory. Yet as their frequency and explanatory weight increase, they weaken trust in the reigning framework. "What makes these upheavals especially striking is that the rival frameworks are often incommensurable--they cannot be measured by the same standards of explanation." When such strain reaches a threshold, resolution does not occur through a simple act of refutation, as strict falsificationism might imply, but through a reorientation in how scientists perceive and organize reality. A scientific revolution occurs when a rival framework arises--not as a minor revision but as a deep re-construction of the conceptual world. The shift is not purely deductive; it resembles a sudden change of perception, like an optical reversal. The shift to heliocentrism, for instance, did not merely refine calculations; it transformed the lens through which celestial movement was interpreted. Likewise, relativity did not merely adjust classical mechanics; it displaced core assumptions about space and time."`, o: [`A minor extension of an older theory`, `A move from specific to general reasoning`, `A radical shift in perception`, `A reversal of chronological order`], e: `The correct option is (c). Meaning in context: The phrase "optical reversal" is used as an analogy. It suggests a situation where the same object is seen differently after a sudden perceptual shift (like a visual illusion that flips). In the passage, this compares to how a new scientific framework changes the way reality is interpreted. The passage says the shift is "not purely deductive" and "resembles a sudden change of perception." Thus, "optical reversal" implies a radical shift in perception, not a small extension or a simple logical step. Examples given: heliocentrism and relativity, which did not merely adjust details but changed the conceptual lens. Why other options are incorrect: (A) Incorrect: A minor extension is the opposite of what the passage emphasizes ("deep re-constructio` },
  { s: `English Language`, q: `According to the passage, why do revolutions disrupt continuity in science? Read the passage and answer the question: "Routine scientific inquiry--the work in which most researchers spend the bulk of their careers--rests on a quiet confidence that the community already possesses a dependable picture of how the world functions. To protect that confidence, investigators often narrow their attention to questions the prevailing framework has already marked as legitimate. When inquiry proceeds in this manner, results are typically incremental: they consolidate the dominant model instead of destabilizing it. Gradually, however, irregular findings--observations that resist explanation within the accepted framework--begin to accumulate. At first, such irregularities are treated as measurement mistakes or puzzles that will eventually be resolved without altering the underlying theory. Yet as their frequency and explanatory weight increase, they weaken trust in the reigning framework. "What makes these upheavals especially striking is that the rival frameworks are often incommensurable--they cannot be measured by the same standards of explanation." When such strain reaches a threshold, resolution does not occur through a simple act of refutation, as strict falsificationism might imply, but through a reorientation in how scientists perceive and organize reality. A scientific revolution occurs when a rival framework arises--not as a minor revision but as a deep re-construction of the conceptual world. The shift is not purely deductive; it resembles a sudden change of perception, like an optical reversal. The shift to heliocentrism, for instance, did not merely refine calculations; it transformed the lens through which celestial movement was interpreted. Likewise, relativity did not merely adjust classical mechanics; it displaced core assumptions about space and time."`, o: [`Because scientists abandon evidence and rely on intuition.`, `Because new frameworks erase all prior discoveries.`, `Because rival frameworks reshape questions and standards, making direct continuity difficult.`, `Because scientists stop engaging in observation.`], e: `The correct option is (c). Explanation (as per passage context): The passage explains that scientific revolutions are not simple corrections inside the same framework. Instead, they involve a deep reorientation in how scientists "perceive and organize reality." During routine science, researchers work within a prevailing framework and produce incremental results. Over time, irregular findings (anomalies) accumulate and strain the accepted framework. When strain becomes strong, a rival framework emerges that is not a minor tweak but a deep reconstruction of the conceptual world. The passage highlights that rival frameworks can be incommensurable, meaning they cannot be judged by the same standards of explanation. This changes what counts as a valid question, acceptable evidence, and proper ` },
  { s: `English Language`, q: `Identify the voice used in the sentence: "Irregularities are treated as measurement mistakes..." Read the passage and answer the question: "Routine scientific inquiry--the work in which most researchers spend the bulk of their careers--rests on a quiet confidence that the community already possesses a dependable picture of how the world functions. To protect that confidence, investigators often narrow their attention to questions the prevailing framework has already marked as legitimate. When inquiry proceeds in this manner, results are typically incremental: they consolidate the dominant model instead of destabilizing it. Gradually, however, irregular findings--observations that resist explanation within the accepted framework--begin to accumulate. At first, such irregularities are treated as measurement mistakes or puzzles that will eventually be resolved without altering the underlying theory. Yet as their frequency and explanatory weight increase, they weaken trust in the reigning framework. "What makes these upheavals especially striking is that the rival frameworks are often incommensurable--they cannot be measured by the same standards of explanation." When such strain reaches a threshold, resolution does not occur through a simple act of refutation, as strict falsificationism might imply, but through a reorientation in how scientists perceive and organize reality. A scientific revolution occurs when a rival framework arises--not as a minor revision but as a deep re-construction of the conceptual world. The shift is not purely deductive; it resembles a sudden change of perception, like an optical reversal. The shift to heliocentrism, for instance, did not merely refine calculations; it transformed the lens through which celestial movement was interpreted. Likewise, relativity did not merely adjust classical mechanics; it displaced core assumptions about space and time."`, o: [`Active voice`, `Passive voice`, `Middle voice`, `Reflexive voice`], e: `The correct option is (b). Concept (Voice): Voice tells whether the subject performs the action (Active) or receives the action (Passive). Passive Voice Structure (basic): Object + is/are/was/were + V3 (past participle) + (by + agent) Given sentence: "Irregularities are treated as measurement mistakes..." Here, the subject "Irregularities" is not doing the action; rather, irregularities are being acted upon (someone treats them as mistakes). The verb phrase are treated = be verb (are) + past participle (treated), which is a clear marker of Passive Voice. The doer/agent is not mentioned, which is common in passive constructions in academic writing. Why other options are incorrect: (A) Active voice: Active would be like "Researchers treat irregularities as measurement mistakes." Here the sub` },
  { s: `English Language`, q: `. What type of clause is used in the sentence: "Findings that resist explanation within the accepted framework begin to accumulate." Read the passage and answer the question: "Routine scientific inquiry--the work in which most researchers spend the bulk of their careers--rests on a quiet confidence that the community already possesses a dependable picture of how the world functions. To protect that confidence, investigators often narrow their attention to questions the prevailing framework has already marked as legitimate. When inquiry proceeds in this manner, results are typically incremental: they consolidate the dominant model instead of destabilizing it. Gradually, however, irregular findings--observations that resist explanation within the accepted framework--begin to accumulate. At first, such irregularities are treated as measurement mistakes or puzzles that will eventually be resolved without altering the underlying theory. Yet as their frequency and explanatory weight increase, they weaken trust in the reigning framework. "What makes these upheavals especially striking is that the rival frameworks are often incommensurable--they cannot be measured by the same standards of explanation." When such strain reaches a threshold, resolution does not occur through a simple act of refutation, as strict falsificationism might imply, but through a reorientation in how scientists perceive and organize reality. A scientific revolution occurs when a rival framework arises--not as a minor revision but as a deep re-construction of the conceptual world. The shift is not purely deductive; it resembles a sudden change of perception, like an optical reversal. The shift to heliocentrism, for instance, did not merely refine calculations; it transformed the lens through which celestial movement was interpreted. Likewise, relativity did not merely adjust classical mechanics; it displaced core assumptions about space and time."`, o: [`Noun clause`, `Adverbial clause`, `Relative clause`, `Independent clause`], e: `The correct option is (c). Concept (Clause Type): A relative clause (also called an adjective clause) describes a noun and often begins with who, which, that, whose, where, when. Given sentence: "Findings that resist explanation within the accepted framework begin to accumulate." The noun being described is Findings. The part "that resist explanation within the accepted framework" begins with that and tells which findings are being referred to. This clause functions like an adjective, qualifying the noun "Findings", hence it is a Relative clause. Why other options are incorrect: (A) Noun clause: A noun clause acts as a noun (subject/object), e.g., "What he said was true." Here the clause is not acting as a noun; it is describing "Findings". (B) Adverbial clause: An adverbial clause modifie` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful passage. 1. Past resolutions are reflected in yearly procedural updates. 2. Administrative proceedings are recorded in secure public ledgers. 3. Measures are escalated after tiered authorizations. 4. Compliance actions are documented at each stage.`, o: [`3-4-2-1`, `2-1-3-4`, `1-3-4-2`, `4-3-1-2`], e: `The correct option is (a). Logical sequence: The sentences describe a controlled administrative/compliance process. The order should move from action initiation to documentation/recording and finally to institutional reflection in future updates. Step 1 (3): "Measures are escalated after tiered authorizations." This indicates the process begins with approvals and escalation of measures; it sets the operational starting point. Step 2 (4): "Compliance actions are documented at each stage." Once measures are taken, compliance documentation is maintained continuously throughout the process. Step 3 (2): "Administrative proceedings are recorded in secure public ledgers." After actions and documentation, the official proceedings are formally recorded in secure records/ledgers for transparency and` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: The department's report is being examined for irregularities by an independent auditor.`, o: [`An independent auditor examined the department's report for irregularities.`, `An independent auditor is examining the department's report for irregularities.`, `An independent auditor was examining the department's report for irregularities.`, `An independent auditor will examine the department's report for irregularities.`], e: `The correct option is (b). Given (Passive): "The department's report is being examined for irregularities by an independent auditor." Identify tense: "is being examined" is Present Continuous Passive. Passive structure: Object + is/are being + V3 + by + agent Active structure: Agent + is/are + V1-ing + object Conversion steps: Make the agent "an independent auditor" the subject in active voice. Change "is being examined" (passive) to "is examining" (active present continuous). Keep the object "the department's report" and the purpose phrase "for irregularities" unchanged. Correct active sentence: "An independent auditor is examining the department's report for irregularities." Why other options are incorrect: (A) simple past ("examined") changes tense and time reference. (C) past continuou` },
  { s: `English Language`, q: `What is the one-word term for: "A literary technique in which a text draws attention to its own fictional status--often through self-reference or characters aware they are part of a story."`, o: [`Metafiction`, `Allegory`, `Realism`, `Parable`], e: `The correct option is (a). Correct one-word term: "Metafiction" is the term for fiction that self-consciously draws attention to its own artificial or fictional nature, often through self-reference or characters aware they are in a story. (Hindi meaning: - / ) Minimum 2-line explanation: Metafiction deliberately breaks the illusion of reality in storytelling. It may comment on the act of writing, address the reader directly, or show characters recognizing the fiction-making process. Example: In a metafictional novel, the narrator may say, "I am creating this scene for you," reminding readers that the story is constructed. Meanings of the given other options: (B) Allegory: a story with a hidden moral or political meaning where characters/events symbolize ideas (Hindi: ). (C) Realism: a styl` },
  { s: `English Language`, q: `Which of the following refers to "a boundary around a black hole beyond which nothing can return"?`, o: [`Wormhole`, `Singularity`, `Event Horizon`, `Nebula`], e: `The correct option is (c). Correct concept: The boundary around a black hole beyond which nothing (not even light) can escape is called the Event Horizon. It marks the "point of no return" for matter and radiation. (Hindi meaning: / ) Why (C) is correct: At the event horizon, the escape velocity becomes equal to the speed of light. Therefore, any object crossing this boundary cannot send information back to the outside observer. Why other options are incorrect: (A) Wormhole: a hypothetical tunnel-like connection between distant regions of spacetime, not the boundary of a black hole (Hindi: ). (B) Singularity: the central point where density is thought to become infinite in classical theory, not the boundary (Hindi: ). (D) Nebula: a cloud of gas and dust in space, unrelated to a black hole ` },
  { s: `English Language`, q: `Why other options are incorrect: (A) Wormhole: a hypothetical tunnel-like connection between distant regions of spacetime, not the boundary of a black hole (Hindi: काल्पिनक सुरंग माग ). (B) Singularity: the central point where density is thought to become infinite in classical theory, not the boundary (Hindi: एकिव दुता). (D) Nebula: a cloud of gas and dust in space, unrelated to a black hole boundary (Hindi: नीहा रका). So the correct answer is (c)`, o: [`Recluse`, `Reclusse`, `Recloose`, `Reclusee`], e: `The correct option is (a). Spelling and meaning: Option (A) "Recluse" is correctly spelt. A recluse is a person who avoids the company of other people and lives in isolation. (Hindi meaning: / ) Example: After retirement, he became a recluse and rarely met anyone. Meanings of all the given options: (A) Recluse: a person living in seclusion (Hindi: ). (B) Reclusse: incorrect spelling (intended word: recluse). (C) Recloose: incorrect spelling (intended word: recluse). (D) Reclusee: incorrect spelling (intended word: recluse). Parts of speech: "Recluse" is commonly used as a noun (a recluse) and can also be used as an adjective in some contexts (recluse lifestyle). So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: His influence (1)/ lasted less than a decade affecting (2)/ major policies (3)/ across departments. (4)/`, o: [`(1)`, `(2)`, `(3)`, `(4)`], e: `The correct option is (b). Error identification: Option (2) "lasted less than a decade" is marked as containing the error because it creates a mismatch in the intended meaning with the participial construction that follows, making the sentence structurally awkward and logically unclear in the given segmented format. Detailed explanation: The sentence is: "His influence lasted less than a decade affecting major policies across departments." After "lasted less than a decade," the phrase "affecting major policies" becomes a dangling/unclear participial phrase because it seems to modify "a decade" (which is illogical) instead of "his influence." To avoid this, the sentence needs a connector or a clearer structure, such as adding "and" or restructuring the clause. One correct rewritten form: "H` },
  { s: `English Language`, q: `Select the most appropriate synonym of the given word: GARRULOUS`, o: [`Loquacious`, `Taciturn`, `Reticent`, `Reserved`], e: `GARRULOUS means excessively talkative. Synonym is Loquacious. Option A.` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful sentence: P: but their use demands caution Q: Machine-learning tools R: have simplified difficult tasks S: in high-stakes domains`, o: [`QSRP`, `QRSP`, `QPRS`, `QPSR`], e: `The correct option is (b). Correct arrangement: Q-R-S-P Formed meaningful sentence: "Machine-learning tools hCaovepysriimghptli©fie2d0d2i6ffAicdudltat2a4s7ks in high-stakes domains but their use demands caution." Why this order is correct (grammar-based explanation): Q must start because it provides the subject phrase "Machine-learning tools." R naturally follows as it contains the main verb phrase "have simplified difficult tasks," completing the core subject­verb­object structure. S is an adverbial/prepositional phrase ("in high-stakes domains") that logically modifies where/under what context the simplification occurs, so it fits after the main clause. P begins with "but," which introduces contrast; it must come after the main idea to oppose it, so it is placed at the end as the contras` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: The advertisement was so unclear that its meaning failed to ___ with viewers.`, o: [`sink on`, `sink out`, `sink in`, `sink over`], e: `The correct option is (c). Correct phrase: "sink in" means to be fully understood or to be mentally processed and accepted. (Hindi meaning: / ) Sentence logic: If the advertisement was unclear, then its meaning did not get understood by viewers; hence "failed to sink in" is the natural and correct phrasal verb. Example: The teacher repeated the concept until it finally sank in for the students. Why other options are incorrect: (A) sink on: Not a standard phrasal verb for "understand." (Meaning not appropriate here.) (B) sink out: Incorrect/unnatural usage in this context; not used to mean "be understood." (D) sink over: Not used idiomatically for comprehension; does not fit the sentence meaning. So the correct answer is (c)` },
  { s: `English Language`, q: `Choose the correct meaning of idiom given below: "Hold someone's feet to the fire"`, o: [`Reward someone generously`, `Press someone to meet demands or answer strictly`, `Offer someone support in trouble`, `Warn someone politely`], e: `The correct option is (b). Given idiom: "Hold someone's feet to the fire" Meaning (minimum 2 lines): This idiom means to put strong pressure on someone so that they must do what is required or give a clear answer/accountability. It suggests strict insistence and no escape from responsibility. (Hindi idiom meaning: / ) Example: The auditor held the contractor's feet to the fireCoupnytirligahlltb©ills2a0n2d6 dAodcduam24e7nts were submitted properly. Why (B) is correct: Option (B) exactly conveys the idea of pressurizing someone to meet demands or answer strictly. Other related idioms and their meanings: Put someone on the spot: force someone to answer immediately. Call someone to account: demand an explanation for actions. Keep someone's nose to the grindstone: make someone work very hard co` },
  { s: `English Language`, q: `A sentence is provided in indirect speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding direct speech. The manager reminded the staff that the concession applied only to those who had submitted a written request.`, o: [`"Only those who submitted a written request can use the concession," the manager said.`, `"If you didn't submit in writing, the concession doesn't apply," the manager reminded them.`, `"The concession applies only to those who made written requests," the manager said.`, `"Those who haven't requested in writing cannot use the concession," said the manager.`], e: `The correct option is (c). Rule (Indirect to Direct Speech): While converting to direct speech: Remove "that" and restore quotation marks. Choose a suitable reporting verb: "reminded" can be converted to "said/reminded" depending on the most accurate and natural direct form given in options. Maintain the original meaning precisely (condition/limitation: applies only to those who submitted a written request). Adjust tense appropriately: "applied" (past) and "had submitted" (past perfect) in indirect speech often correspond to a direct speech form that can be expressed in present simple when stating a general rule/condition, which is commonly done in exam options. Given indirect speech: "The manager reminded the staff that the concession applied only to those who had submitted a written requ` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The supposedly transparent framework (1)/ for public consultation (2)/ paradoxically obscuring (3)/ the very issues it claimed to clarify. (4)/`, o: [`(1)`, `(2)`, `(3)`, `(4)`], e: `The correct option is (c). Error identification: Option (3) "paradoxically obscuring" is grammatically incorrect in the given sentence structure because it breaks the required verb form for the main clause. Why it is an error: The sentence begins with the subject: "The supposedly transparent framework ..." After the subject and modifiers, we need a finite verb (a main verb that shows tense), such as is/was/has been etc. But "paradoxically obscuring" is a present participle (-ing form) and cannot serve as the main verb here without an auxiliary. Hence, the sentence becomes a fragment and does not complete the grammatical structure. Correct form (one acceptable correction): "The supposedly transparent framework for public consultation was paradoxically obscuring the very issues it claimed to` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: The material had been being assembled for days before the launch.`, o: [`They were assembling the material for days before the launch.`, `They had been assembling the material for days before the launch.`, `They had assembled the material for days before the launch.`, `They had been assembled the material for days before the launch.`], e: `The correct option is (b). Given (Passive): "The material had been being assembled for days before the launch." Identify tense and structure: "had been being assembled" is Past Perfect Continuous Passive. Passive structure: Object + had been being + V3 Active structure: Subject + had been + V1-ing + object Conversion steps (Passive to Active): Make the object "the material" the object again in active. Add a suitable subject like "they" (agent is not given, so a general subject is used). Convert "had been being assembled" to "had been assembling." Keep the time expression "for days before the launch" unchanged because it shows duration and time reference. Correct active sentence: "They had been assembling the material for days before the launch." Why other options are incorrect: (A) "were a` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Graduate Level)',
      code: 'SSC-SSP',
      description: 'Staff Selection Commission - Selection Post (Graduate Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Graduate Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Graduation) - 29 July 2025 Shift-3 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Graduate', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '3',
    pyqExamName: 'SSC Selection Post Phase XIII (Graduate) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
